class RippleEffect{constructor(selector='.premium-btn-ripple'){this.selector=selector;this.init();}init(){document.addEventListener('click',(e)=>{const button=e.target.closest(this.selector);if(!button)return;this.createRipple(button,e);});}createRipple(button,event){const ripple=document.createElement('span');const rect=button.getBoundingClientRect();const size=Math.max(rect.width,rect.height);const x=event.clientX-rect.left-size/2;const y=event.clientY-rect.top-size/2;ripple.style.cssText=` position: absolute;width: ${size}px;height: ${size}px;left: ${x}px;top: ${y}px;border-radius: 50%;background: rgba(255,255,255,0.3);transform: scale(0);animation: ripple-animation 0.6s ease-out;pointer-events: none;`;button.appendChild(ripple);ripple.addEventListener('animationend',()=>{ripple.remove();});}static init(selector){return new RippleEffect(selector);}}const style=document.createElement('style');style.textContent=` @keyframes ripple-animation{to{transform: scale(4);opacity: 0;}}`;document.head.appendChild(style);class TiltEffect{constructor(selector='.premium-card-tilt'){this.selector=selector;this.elements=[];this.init();}init(){const elements=document.querySelectorAll(this.selector);elements.forEach((el)=>{this.elements.push({element: el,rect: el.getBoundingClientRect()});this.bindEvents(el);});window.addEventListener('resize',()=>{this.elements.forEach((item)=>{item.rect=item.element.getBoundingClientRect();});});}bindEvents(element){element.addEventListener('mousemove',(e)=>this.onMouseMove(e,element));element.addEventListener('mouseleave',()=>this.onMouseLeave(element));}onMouseMove(e,element){const rect=element.getBoundingClientRect();const x=e.clientX-rect.left;const y=e.clientY-rect.top;const centerX=rect.width/2;const centerY=rect.height/2;const rotateX=(y-centerY)/10;const rotateY=(centerX-x)/10;element.style.transform=`perspective(1000px)rotateX(${rotateX}deg)rotateY(${rotateY}deg)scale(1.02)`;}onMouseLeave(element){element.style.transform='perspective(1000px)rotateX(0)rotateY(0)scale(1)';}static init(selector){return new TiltEffect(selector);}}class CounterAnimation{constructor(){this.observers=[];this.init();}init(){const counters=document.querySelectorAll('[data-counter-target]');const observer=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){this.animateCounter(entry.target);observer.unobserve(entry.target);}});},{threshold: 0.5});counters.forEach((counter)=>observer.observe(counter));}animateCounter(element){const target=parseInt(element.dataset.counterTarget,10);const duration=2000;const step=target/(duration/16);let current=0;const update=()=>{current+=step;if(current<target){element.textContent=Math.floor(current).toLocaleString('vi-VN');requestAnimationFrame(update);}else{element.textContent=target.toLocaleString('vi-VN');}};requestAnimationFrame(update);}static init(){return new CounterAnimation();}}class ParallaxScroll{constructor(selector='.premium-parallax'){this.selector=selector;this.elements=[];this.init();}init(){const elements=document.querySelectorAll(this.selector);elements.forEach((el)=>{const speed=parseFloat(el.dataset.parallaxSpeed||'0.5');this.elements.push({element: el,speed});});window.addEventListener('scroll',()=>this.onScroll(),{passive: true});}onScroll(){const scrolled=window.pageYOffset;this.elements.forEach((item)=>{const rect=item.element.getBoundingClientRect();const offset=(scrolled-rect.top)*item.speed;item.element.style.transform=`translateY(${offset}px)`;});}static init(selector){return new ParallaxScroll(selector);}}class MagneticButton{constructor(selector='.premium-magnetic'){this.selector=selector;this.init();}init(){const buttons=document.querySelectorAll(this.selector);buttons.forEach((button)=>this.bindEvents(button));}bindEvents(button){button.addEventListener('mousemove',(e)=>this.onMouseMove(e,button));button.addEventListener('mouseleave',()=>this.onMouseLeave(button));}onMouseMove(e,button){const rect=button.getBoundingClientRect();const x=e.clientX-rect.left-rect.width/2;const y=e.clientY-rect.top-rect.height/2;button.style.transform=`translate(${x*0.3}px,${y*0.3}px)`;}onMouseLeave(button){button.style.transform='translate(0,0)';}static init(selector){return new MagneticButton(selector);}}class TextReveal{constructor(selector='.premium-text-reveal'){this.selector=selector;this.init();}init(){const elements=document.querySelectorAll(this.selector);elements.forEach((el)=>this.splitText(el));}splitText(element){const text=element.textContent;element.textContent='';text.split('').forEach((char,index)=>{const span=document.createElement('span');span.textContent=char===' ' ? '\u00A0' : char;span.style.cssText=` display: inline-block;opacity: 0;transform: translateY(20px);animation: textRevealAnim 0.5s ease forwards;animation-delay: ${index*0.05}s;`;element.appendChild(span);});}static init(selector){return new TextReveal(selector);}}const textRevealStyle=document.createElement('style');textRevealStyle.textContent=` @keyframes textRevealAnim{to{opacity: 1;transform: translateY(0);}}`;document.head.appendChild(textRevealStyle);class ScrollProgress{constructor(selector='.premium-scroll-progress'){this.selector=selector;this.progressBar=null;this.init();}init(){this.progressBar=document.querySelector(this.selector);if(!this.progressBar)return;window.addEventListener('scroll',()=>this.update(),{passive: true});this.update();}update(){const scrollTop=window.pageYOffset;const docHeight=document.documentElement.scrollHeight-window.innerHeight;const scrollPercent=(scrollTop/docHeight)*100;this.progressBar.style.width=`${scrollPercent}%`;}static init(selector){return new ScrollProgress(selector);}}class LazyLoadAnimate{constructor(selector='.premium-lazy'){this.selector=selector;this.init();}init(){const images=document.querySelectorAll(this.selector);const observer=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){this.loadImage(entry.target);observer.unobserve(entry.target);}});},{threshold: 0.1});images.forEach((img)=>observer.observe(img));}loadImage(img){const src=img.dataset.src;if(!src)return;img.classList.add('loading');const loadedImg=new Image();loadedImg.onload=()=>{img.src=src;img.classList.remove('loading');img.classList.add('loaded');};loadedImg.src=src;}static init(selector){return new LazyLoadAnimate(selector);}}const PremiumInteractions={RippleEffect,TiltEffect,CounterAnimation,ParallaxScroll,MagneticButton,TextReveal,ScrollProgress,LazyLoadAnimate,initAll(){document.addEventListener('DOMContentLoaded',()=>{new RippleEffect();new CounterAnimation();new ScrollProgress();});}};export{PremiumInteractions};export default PremiumInteractions;PremiumInteractions.initAll();